Here are the public test cases for feature4_state_change_detection:
{
  "description": "Comparing current file hashes against a stored baseline reports added, modified, and removed paths.",
  "cases": [
    {
      "description": "Mixed current and baseline states produce one added, one modified, and one removed change.",
      "input": {
        "command": "state.compare",
        "current": {
          "same.md": "aaa",
          "changed.md": "new",
          "added.md": "sha"
        },
        "baseline": {
          "same.md": "aaa",
          "changed.md": "old",
          "removed.md": "gone"
        }
      },
      "expected_output": "added.md=ADDED\nchanged.md=MODIFIED\nremoved.md=REMOVED\n"
    }
  ]
}

Here are the public test cases for feature5_change_resolution:
{
  "description": "Local and remote change lists are separated into safe pushes, safe pulls, and clashes using protected-path and untracked-file checks.",
  "cases": [
    {
      "description": "A local-only update, remote-only update, protected remote update, and both-sides update are categorized separately.",
      "input": {
        "command": "state.resolve",
        "localChanges": [
          {
            "path": "local.md",
            "type": "ADDED"
          },
          {
            "path": "both.md",
            "type": "MODIFIED"
          }
        ],
        "remoteChanges": [
          {
            "path": "remote.md",
            "type": "ADDED"
          },
          {
            "path": "both.md",
            "type": "MODIFIED"
          },
          {
            "path": ".obsidian/app.json",
            "type": "ADDED"
          }
        ],
        "localScanPaths": [
          "local.md",
          "both.md"
        ],
        "protectedPaths": [
          ".obsidian/app.json"
        ],
        "filesystemState": [
          {
            "path": "remote.md",
            "exists": false
          }
        ],
        "baselineShas": {}
      },
      "expected_output": "checks=[{\"path\":\"remote.md\",\"remoteOp\":\"ADDED\"}]\nsafe_local=[{\"path\":\"local.md\",\"type\":\"ADDED\"}]\nsafe_remote=[{\"path\":\"remote.md\",\"type\":\"ADDED\"}]\nclashes=[{\"localState\":\"MODIFIED\",\"path\":\"both.md\",\"remoteOp\":\"MODIFIED\"},{\"localState\":\"protected\",\"path\":\".obsidian/app.json\",\"remoteOp\":\"ADDED\"}]\n"
    }
  ]
}

